117	// enrichWorkersWithRunState fills bead/attempt/worktree from a fresh
118	// per-attempt run-state record (.ddx/run-state/<attempt>.json) whose PID
119	// matches a live worker, when liveness enrichment did not supply them — e.g.
120	// the liveness sidecar was absent, start-time-skewed, or its attempt id was
121	// stale (ddx-f9b41107). Run-state is read from each worker's own project root,
122	// so all-projects scope does not leak attempts across projects.
123	func enrichWorkersWithRunState(workers []workerstatus.LiveWorker, now time.Time) []workerstatus.LiveWorker {
124		byProject := make(map[string][]agent.RunState)
125		for i := range workers {
126			w := &workers[i]
127			if w.PID <= 0 || (w.BeadID != "" && w.AttemptID != "" && w.ExecutionWorktree != "") {
128				continue
129			}
130			states, ok := byProject[w.ProjectRoot]
131			if !ok {
132				states, _ = agent.ReadRunStates(w.ProjectRoot)
133				byProject[w.ProjectRoot] = states
134			}
135			rec, ok := freshestRunStateForPID(states, w.PID, now)
136			if !ok {
137				continue
138			}
139			if w.BeadID == "" {
140				w.BeadID = rec.BeadID
141			}
142			if w.AttemptID == "" {
143				w.AttemptID = rec.AttemptID
144			}
145			if w.ExecutionWorktree == "" {
146				w.ExecutionWorktree = rec.WorktreePath
147			}
148		}
149		return workers
150	}
