152	// freshestRunStateForPID returns the most recently refreshed non-expired
153	// run-state record for pid, if any.
154	func freshestRunStateForPID(states []agent.RunState, pid int, now time.Time) (agent.RunState, bool) {
155		var best agent.RunState
156		found := false
157		for _, s := range states {
158			if s.PID != pid {
159				continue
160			}
161			if !s.ExpiresAt.IsZero() && now.After(s.ExpiresAt) {
162				continue
163			}
164			if !found || s.RefreshedAt.After(best.RefreshedAt) {
165				best = s
166				found = true
167			}
168		}
169		return best, found
170	}
