172	func filterAndSortWorkers(all []workerstatus.LiveWorker, projectRoot string, allProjects bool) []workerstatus.LiveWorker {
173		var filtered []workerstatus.LiveWorker
174		if allProjects {
175			filtered = append(filtered, all...)
176		} else {
177			filtered = workerstatus.FilterByProject(all, projectRoot)
178		}
179		sort.SliceStable(filtered, func(i, j int) bool {
180			if filtered[i].StartedAt.Equal(filtered[j].StartedAt) {
181				return filtered[i].PID < filtered[j].PID
182			}
183			return filtered[i].StartedAt.Before(filtered[j].StartedAt)
184		})
185		return filtered
186	}
