 14	// LivenessRecord is the worker-side sidecar written under
 15	// .ddx/workers/<worker-id>/status.json to mirror live progress of a
 16	// long-running ddx work / ddx try attempt without rewriting beads.jsonl.
 17	//
 18	// The bead tracker remains the durable claim marker; this sidecar carries
 19	// the high-frequency liveness signal so operators can answer "is the worker
 20	// alive and what is it doing?" without inflating tracker churn.
 21	type LivenessRecord struct {
 22		WorkerID       string    `json:"worker_id"`
 23		ProjectRoot    string    `json:"project_root,omitempty"`
 24		CurrentBead    string    `json:"current_bead,omitempty"`
 25		AttemptID      string    `json:"attempt_id,omitempty"`
 26		Phase          string    `json:"phase,omitempty"`
 27		Message        string    `json:"message,omitempty"`
 28		Route          string    `json:"route,omitempty"`
 29		Harness        string    `json:"harness,omitempty"`
 30		Model          string    `json:"model,omitempty"`
 31		Profile        string    `json:"profile,omitempty"`
 32		PID            int       `json:"pid,omitempty"`
 33		ChildPID       int       `json:"child_pid,omitempty"`
 34		StartedAt      time.Time `json:"started_at,omitempty"`
 35		LastActivityAt time.Time `json:"last_activity_at"`
 36	}
 37	
 38	// LivenessTTL is the freshness window for treating a worker sidecar as
 39	// "active". Defaults to 3× the bead tracker heartbeat interval (which is
 40	// 30s) so a sidecar that has not been touched in ~90s is treated as stale.
 41	var LivenessTTL = 90 * time.Second
 42	
 43	// LivenessDir returns the worker sidecar directory for a project.
 44	func LivenessDir(projectRoot string) string {
 45		return ddxroot.JoinProject(projectRoot, "workers")
 46	}
 47	
 48	// LivenessPath returns the status.json path for a worker under projectRoot.
 49	func LivenessPath(projectRoot, workerID string) string {
 50		return filepath.Join(LivenessDir(projectRoot), workerID, "status.json")
 51	}
 52	
 53	// WriteLiveness writes rec to .ddx/workers/<workerID>/status.json using a
 54	// tmp-then-rename so concurrent readers never see a half-written file.
 55	func WriteLiveness(projectRoot, workerID string, rec LivenessRecord) error {
 56		if projectRoot == "" || workerID == "" {
 57			return fmt.Errorf("workerstatus: project root and worker id required")
 58		}
 59		dir := filepath.Join(LivenessDir(projectRoot), workerID)
 60		if err := os.MkdirAll(dir, 0o755); err != nil {
 61			return fmt.Errorf("workerstatus: mkdir worker dir: %w", err)
 62		}
 63		data, err := json.MarshalIndent(rec, "", "  ")
 64		if err != nil {
 65			return fmt.Errorf("workerstatus: marshal liveness: %w", err)
 66		}
 67		data = append(data, '\n')
 68		final := filepath.Join(dir, "status.json")
 69		tmp, err := os.CreateTemp(dir, "status-*.tmp")
 70		if err != nil {
 71			return fmt.Errorf("workerstatus: create tmp: %w", err)
 72		}
 73		tmpName := tmp.Name()
 74		if _, err := tmp.Write(data); err != nil {
 75			_ = tmp.Close()
 76			_ = os.Remove(tmpName)
 77			return fmt.Errorf("workerstatus: write tmp: %w", err)
 78		}
 79		if err := tmp.Close(); err != nil {
 80			_ = os.Remove(tmpName)
 81			return fmt.Errorf("workerstatus: close tmp: %w", err)
 82		}
 83		if err := os.Rename(tmpName, final); err != nil {
 84			_ = os.Remove(tmpName)
 85			return fmt.Errorf("workerstatus: rename: %w", err)
 86		}
 87		return nil
 88	}
 89	
 90	// ReadLiveness reads the sidecar for workerID under projectRoot.
 91	func ReadLiveness(projectRoot, workerID string) (LivenessRecord, error) {
 92		var rec LivenessRecord
 93		data, err := os.ReadFile(LivenessPath(projectRoot, workerID))
 94		if err != nil {
 95			return rec, err
 96		}
 97		if err := json.Unmarshal(data, &rec); err != nil {
 98			return rec, fmt.Errorf("workerstatus: parse liveness: %w", err)
 99		}
100		return rec, nil
101	}
102	
103	// ListLiveness reads every status.json sidecar under projectRoot's worker
104	// directory. Malformed sidecars are skipped silently — the sidecar is
105	// best-effort observability, not authoritative state.
106	func ListLiveness(projectRoot string) ([]LivenessRecord, error) {
107		dir := LivenessDir(projectRoot)
108		entries, err := os.ReadDir(dir)
109		if err != nil {
110			if os.IsNotExist(err) {
111				return nil, nil
112			}
113			return nil, err
114		}
115		var out []LivenessRecord
116		for _, entry := range entries {
117			if !entry.IsDir() {
118				continue
119			}
120			rec, err := ReadLiveness(projectRoot, entry.Name())
121			if err != nil {
122				continue
123			}
124			out = append(out, rec)
125		}
126		sort.Slice(out, func(i, j int) bool {
127			return out[i].LastActivityAt.After(out[j].LastActivityAt)
128		})
129		return out, nil
130	}
