132	// IsFresh reports whether rec.LastActivityAt is within LivenessTTL of now.
133	func (r LivenessRecord) IsFresh(now time.Time) bool {
134		if r.LastActivityAt.IsZero() {
135			return false
136		}
137		return now.Sub(r.LastActivityAt) <= LivenessTTL
138	}

