1079	func (m *WorkerManager) List() ([]WorkerRecord, error) {
1080		if err := os.MkdirAll(m.rootDir, 0o755); err != nil {
1081			return nil, err
1082		}
1083		entries, err := os.ReadDir(m.rootDir)
1084		if err != nil {
1085			return nil, err
1086		}
1087		var out []WorkerRecord
1088		for _, entry := range entries {
1089			if !entry.IsDir() {
1090				continue
1091			}
1092			rec, err := m.readRecord(filepath.Join(m.rootDir, entry.Name()))
1093			if err != nil {
1094				continue
1095			}
1096			if !isWorkerRegistryRecord(rec) {
1097				continue
1098			}
1099			out = append(out, rec)
1100		}
1101	
1102		// Merge in-memory state for active workers
1103		m.mu.Lock()
1104		for i := range out {
1105			if handle, ok := m.workers[out[i].ID]; ok {
1106				out[i] = handle.record
1107			}
1108		}
1109		m.mu.Unlock()
1110	
1111		sort.Slice(out, func(i, j int) bool {
1112			return out[i].StartedAt.After(out[j].StartedAt)
1113		})
1114	
1115		// Compute PIDAlive for each record so operators can see liveness at a
1116		// glance without running prune. This is a syscall per record; it's safe
1117		// because List() is not on a hot path (workers are long-lived).
1118		for i := range out {
1119			if out[i].PID > 0 {
1120				alive := isPIDAlive(out[i].PID)
1121				out[i].PIDAlive = &alive
1122			}
1123		}
1124	
1125		return out, nil
1126	}
