 45	// GetReportedWorkers implements ddxgraphql.ReportedWorkersProvider.
 46	// Returns workers from the ingest registry plus synthesized active workers
 47	// from live run-state.json files. The reportedWorkers query shows both
 48	// registered worker reports (from the worker-server HTTP interface, ADR-022)
 49	// and in-flight attempts (from run-state.json for inline work).
 50	func (a *reportedWorkersAdapter) GetReportedWorkers() []*ddxgraphql.ReportedWorker {
 51		if a.reg == nil {
 52			return nil
 53		}
 54		now := a.currentNow()
 55		snap := a.reg.snapshot()
 56		out := make([]*ddxgraphql.ReportedWorker, 0, len(snap))
 57		for _, rec := range snap {
 58			w := &ddxgraphql.ReportedWorker{
 59				ID:                  rec.WorkerID,
 60				Project:             rec.Identity.ProjectRoot,
 61				Harness:             rec.Identity.Harness,
 62				State:               freshnessState(rec, now),
 63				LastEventAt:         rec.LastEventAt.UTC().Format(time.RFC3339Nano),
 64				MirrorFailuresCount: rec.MirrorFailuresCount,
 65				HadDroppedBackfill:  rec.HadDroppedBackfill,
 66			}
 67			if rec.CurrentBead != "" {
 68				cb := rec.CurrentBead
 69				w.CurrentBead = &cb
 70			}
