 87	// getInFlightWorkers returns synthesized ReportedWorker entries for each
 88	// live attempt in run-state.json that has not yet expired.
 89	func (a *reportedWorkersAdapter) getInFlightWorkers(now time.Time) []*ddxgraphql.ReportedWorker {
 90		runStateDir := ddxroot.JoinProject(a.workingDir, agent.RunStateDirName)
 91		entries, err := os.ReadDir(runStateDir)
 92		if err != nil {
 93			return nil
 94		}
 95	
 96		var out []*ddxgraphql.ReportedWorker
 97		for _, entry := range entries {
 98			if entry.IsDir() || filepath.Ext(entry.Name()) != ".json" {
 99				continue
100			}
101			data, err := os.ReadFile(filepath.Join(runStateDir, entry.Name()))
102			if err != nil {
103				continue
104			}
105			var state agent.RunState
106			if err := json.Unmarshal(data, &state); err != nil {
107				continue
108			}
109			// Skip expired runs.
110			if !state.ExpiresAt.IsZero() && now.After(state.ExpiresAt) {
111				continue
112			}
113			// Synthesize a ReportedWorker from the run-state.
114			w := &ddxgraphql.ReportedWorker{
115				ID:          "inline-" + state.AttemptID,
116				Project:     a.workingDir,
117				Harness:     state.Harness,
118				State:       "connected",
119				LastEventAt: state.RefreshedAt.UTC().Format(time.RFC3339Nano),
120			}
121			if state.BeadID != "" {
122				b := state.BeadID
123				w.CurrentBead = &b
124			}
125			if state.AttemptID != "" {
126				att := state.AttemptID
127				w.CurrentAttempt = &att
128			}
129			out = append(out, w)
130		}
131		return out
132	}

320		}
