325	
326		// Section: Active workers (sidecar-derived). Surfaced so an operator
327		// asking "is the worker alive?" gets a positive answer even when the
328		// bead tracker's claim timestamp has not advanced.
329		if len(r.ActiveWorkers) > 0 {
330			fmt.Fprintf(out, "\n=== Active workers (%d) ===\n", len(r.ActiveWorkers))
331			for _, w := range r.ActiveWorkers {
332				fmt.Fprintf(out, "  [%s] bead=%s attempt=%s phase=%s last=%s\n",
333					w.WorkerID, dashIfEmpty(w.CurrentBead), dashIfEmpty(w.AttemptID),
334					dashIfEmpty(w.Phase), w.LastActivityAt)
335			}
336		}
337	
338		// Section: Worker recommendation
339		fmt.Fprintf(out, "\n=== Worker recommendation ===\n")
340		fmt.Fprintf(out, "  %s\n", r.WorkerRecommendation)
341	
342		// Section: Unknowns
343		fmt.Fprintf(out, "\n=== Unknowns ===\n")
344		if len(r.Unknowns) == 0 {
345			fmt.Fprintln(out, "  (none)")
346		} else {
347			for _, u := range r.Unknowns {
348				fmt.Fprintf(out, "  - %s\n", u)
349			}
350		}
351	
352		return nil
353	}
