 83	// LifecycleQueueDecision is the pure result of evaluating LifecycleQueueFacts.
 84	type LifecycleQueueDecision struct {
 85		Bucket                LifecycleQueueBucket
 86		WorkerEligible        bool
 87		OperatorAttention     bool
 88		DependenciesSatisfied bool
 89		SatisfiesDependents   bool
 90		Issues                []LifecycleIssue
 91		Warnings              []string
 92		ExternalBlockerReason string
 93	}
 94	
 95	// ValidateLifecycleTransition returns nil when from -> to is a valid persisted
 96	// status transition under the supplied explicit facts.
 97	func ValidateLifecycleTransition(from, to string, opts LifecycleTransitionOptions) error {
 98		if err := validateLifecycleStatus(from); err != nil {
 99			return err
100		}
101		if err := validateLifecycleStatus(to); err != nil {
102			return err
103		}
104		if from == to {
105			return nil
106		}
107		if to == StatusClosed && opts.ManualClose {
108			switch from {
109			case StatusOpen, StatusInProgress, StatusBlocked, StatusProposed:
110				return nil
111			}
112		}
113		if from == StatusClosed && to == StatusOpen && opts.ManualReopen {
114			return nil
115		}
116		if from == StatusClosed || from == StatusCancelled {
117			return lifecycleTransitionError(LifecycleIssueTransitionFromTerminal, from, to)
118		}
119		if to == StatusProposed && !opts.OperatorRequired {
120			return lifecycleTransitionError(LifecycleIssueTransitionRequiresOperator, from, to)
121		}
122		if to == StatusBlocked && strings.TrimSpace(opts.ExternalBlockerReason) == "" {
123			return lifecycleTransitionError(LifecycleIssueTransitionRequiresExternal, from, to)
124		}
125		if lifecycleTransitionAllowed(from, to) {
126			return nil
127		}
128		return lifecycleTransitionError(LifecycleIssueTransitionUnsupported, from, to)
129	}
130	
131	// LifecycleStatusSatisfiesDependency reports whether a persisted status
132	// satisfies dependent beads. Only closed satisfies dependents.
133	func LifecycleStatusSatisfiesDependency(status string) bool {
134		return status == StatusClosed
135	}
136	
137	// LifecycleDependenciesSatisfied reports whether every dependency is closed.
138	func LifecycleDependenciesSatisfied(deps []LifecycleDependencyState) bool {
139		for _, dep := range deps {
140			if !LifecycleStatusSatisfiesDependency(dep.Status) {
141				return false
142			}
143		}
144		return true
145	}
146	
147	// EvaluateLifecycleQueue derives queue state from caller-provided facts. Legacy
148	// lifecycle labels are reported as warnings only; they never choose the bucket.
149	func EvaluateLifecycleQueue(f LifecycleQueueFacts) LifecycleQueueDecision {
150		decision := LifecycleQueueDecision{
151			DependenciesSatisfied: LifecycleDependenciesSatisfied(f.Dependencies),
152			SatisfiesDependents:   LifecycleStatusSatisfiesDependency(f.Status),
153		}
154		decision.Warnings = append(decision.Warnings, lifecycleLegacyLabelWarnings(f.LegacyLabels)...)
155		for _, warning := range f.LegacyMigrationWarnings {
156			trimmed := strings.TrimSpace(warning)
157			if trimmed == "" {
158				continue
159			}
160			decision.Issues = append(decision.Issues, LifecycleIssue{
161				Code:   LifecycleIssueLegacyMigrationCompatibility,
162				Detail: trimmed,
163			})
164			decision.Warnings = append(decision.Warnings, trimmed)
165		}
166	
167		if err := validateLifecycleStatus(f.Status); err != nil {
168			decision.Bucket = LifecycleBucketInvalid
169			decision.Issues = append(decision.Issues, LifecycleIssue{
170				Code:   LifecycleIssueInvalidStatus,
171				Detail: err.Error(),
172			})
173			return decision
174		}
175	
176		switch f.Status {
177		case StatusClosed:
178			decision.Bucket = LifecycleBucketClosedTerminal
179		case StatusCancelled:
180			decision.Bucket = LifecycleBucketCancelledTerminal
181		case StatusProposed:
182			decision.Bucket = LifecycleBucketProposed
183			decision.OperatorAttention = true
184		case StatusInProgress:
185			if f.ClaimFresh {
186				decision.Bucket = LifecycleBucketClaimed
187				return decision
188			}
189			decision = evaluateOpenLifecycleQueue(f, decision)
190		case StatusBlocked:
191			decision.Bucket = LifecycleBucketBlockedExternal
192			decision.ExternalBlockerReason = strings.TrimSpace(f.ExternalBlockerReason)
193			if decision.ExternalBlockerReason == "" {
194				decision.Issues = append(decision.Issues, LifecycleIssue{
195					Code:   LifecycleIssueBlockedMissingExternalReason,
196					Detail: "blocked status requires an explicit external blocker reason",
197				})
198			}
199		case StatusOpen:
200			if f.ClaimFresh {
201				decision.Bucket = LifecycleBucketClaimed
202				return decision
203			}
204			decision = evaluateOpenLifecycleQueue(f, decision)
205		}
206		return decision
207	}
208	
209	func evaluateOpenLifecycleQueue(f LifecycleQueueFacts, decision LifecycleQueueDecision) LifecycleQueueDecision {
210		if !decision.DependenciesSatisfied {
211			decision.Bucket = LifecycleBucketWaitingDependencies
212			return decision
213		}
214		if strings.TrimSpace(f.SupersededBy) != "" {
215			decision.Bucket = LifecycleBucketSuperseded
216			return decision
217		}
218		if f.EpicContainer {
219			decision.Bucket = LifecycleBucketEpicContainer
220			return decision
221		}
222		if f.RetryCooldownActive {
223			decision.Bucket = LifecycleBucketRetryCooldown
224			return decision
225		}
226		if f.ExecutionEligibleKnown && !f.ExecutionEligible {
227			decision.Bucket = LifecycleBucketNotEligible
228			return decision
229		}
230		decision.Bucket = LifecycleBucketReady
231		decision.WorkerEligible = true
232		return decision
233	}
234	
235	func validateLifecycleStatus(status string) error {
236		if IsCanonicalStatus(status) {
237			return nil
238		}
239		return fmt.Errorf("%s: %q", LifecycleIssueInvalidStatus, status)
240	}
241	
242	func lifecycleTransitionAllowed(from, to string) bool {
243		switch from {
244		case StatusProposed:
245			return to == StatusOpen || to == StatusCancelled
246		case StatusOpen:
247			return to == StatusInProgress || to == StatusBlocked || to == StatusProposed || to == StatusCancelled
248		case StatusInProgress:
249			return to == StatusOpen || to == StatusClosed || to == StatusBlocked || to == StatusProposed
250		case StatusBlocked:
251			return to == StatusOpen || to == StatusProposed || to == StatusCancelled
252		default:
253			return false
254		}
255	}
256	
257	func lifecycleTransitionError(code LifecycleIssueCode, from, to string) error {
258		return fmt.Errorf("%s: %s -> %s", code, from, to)
259	}
