 13	const claimLivenessNamespace = "ddx-claim-heartbeats"
 14	
 15	// claimLeaseSameMachineFallbackAge is the hard ceiling after which a same
 16	// machine + live PID lease stops blocking takeover and we fall back to age.
 17	// It stays comfortably above the lock-hold caps enforced elsewhere.
 18	const claimLeaseSameMachineFallbackAge = 2 * time.Hour
 19	
 20	type ClaimLeaseRecord struct {
 21		BeadID    string    `json:"bead_id"`
 22		Owner     string    `json:"owner,omitempty"`
 23		Session   string    `json:"session,omitempty"`
 24		Worktree  string    `json:"worktree,omitempty"`
 25		Machine   string    `json:"machine,omitempty"`
 26		StartedAt time.Time `json:"started_at,omitempty"`
 27		UpdatedAt time.Time `json:"updated_at"`
 28		PID       int       `json:"pid,omitempty"`
 29	}
 30	
 31	func claimLivenessPath(ddxDir, id string) string {
 32		root := canonicalClaimRoot(ddxDir)
 33		sum := sha1.Sum([]byte(root))
 34		return filepath.Join(os.TempDir(), claimLivenessNamespace, hex.EncodeToString(sum[:]), id+".json")
 35	}
 36	
 37	func canonicalClaimRoot(ddxDir string) string {
 38		root := filepath.Clean(filepath.Dir(ddxDir))
 39		if abs, err := filepath.Abs(root); err == nil {
 40			root = abs
 41		}
 42		if real, err := filepath.EvalSymlinks(root); err == nil {
 43			root = real
 44		}
 45		return filepath.Clean(root)
 46	}
 47	
 48	func currentMachineID() string {
 49		machine, _ := os.Hostname()
 50		if envID := os.Getenv("DDX_MACHINE_ID"); envID != "" {
 51			machine = envID
 52		}
 53		return machine
 54	}
 55	
 56	func writeAtomicClaimFile(path string, data []byte) error {
 57		dir := filepath.Dir(path)
 58		if err := os.MkdirAll(dir, 0o755); err != nil {
 59			return fmt.Errorf("bead: mkdir claim liveness dir: %w", err)
 60		}
 61		tmp, err := os.CreateTemp(dir, filepath.Base(path)+".tmp-*")
 62		if err != nil {
 63			return fmt.Errorf("bead: create claim liveness tmp: %w", err)
 64		}
 65		tmpName := tmp.Name()
 66		defer func() {
 67			_ = tmp.Close()
 68			_ = os.Remove(tmpName)
 69		}()
 70		if _, err := tmp.Write(data); err != nil {
 71			return fmt.Errorf("bead: write claim liveness tmp: %w", err)
 72		}
 73		if err := tmp.Close(); err != nil {
 74			return fmt.Errorf("bead: close claim liveness tmp: %w", err)
 75		}
 76		if err := os.Rename(tmpName, path); err != nil {
 77			return fmt.Errorf("bead: publish claim liveness: %w", err)
 78		}
 79		return nil
 80	}
 81	
 82	func (s *Store) writeClaimHeartbeat(rec ClaimLeaseRecord) error {
 83		data, err := json.Marshal(rec)
 84		if err != nil {
 85			return fmt.Errorf("bead: marshal claim liveness: %w", err)
 86		}
 87		data = append(data, '\n')
 88		return writeAtomicClaimFile(claimLivenessPath(s.Dir, rec.BeadID), data)
 89	}
 90	
 91	func (s *Store) readClaimHeartbeat(id string) (ClaimLeaseRecord, bool, error) {
 92		data, err := os.ReadFile(claimLivenessPath(s.Dir, id))
 93		if os.IsNotExist(err) {
 94			return ClaimLeaseRecord{}, false, nil
 95		}
 96		if err != nil {
 97			return ClaimLeaseRecord{}, false, fmt.Errorf("bead: read claim liveness: %w", err)
 98		}
 99		var rec ClaimLeaseRecord
100		if err := json.Unmarshal(data, &rec); err != nil {
101			return ClaimLeaseRecord{}, true, fmt.Errorf("bead: parse claim liveness: %w", err)
102		}
103		return rec, true, nil
104	}
105	
106	func (s *Store) upsertClaimHeartbeat(id string, mutate func(*ClaimLeaseRecord)) error {
107		rec, found, err := s.readClaimHeartbeat(id)
108		if err != nil {
109			return err
110		}
111		now := time.Now().UTC()
112		if !found {
113			rec = ClaimLeaseRecord{
114				BeadID:    id,
115				StartedAt: now,
116			}
117		}
118		if rec.BeadID == "" {
119			rec.BeadID = id
120		}
121		if rec.StartedAt.IsZero() {
122			rec.StartedAt = now
123		}
124		rec.UpdatedAt = now
125		if rec.PID == 0 {
126			rec.PID = os.Getpid()
127		}
128		if mutate != nil {
129			mutate(&rec)
130		}
131		data, err := json.Marshal(rec)
132		if err != nil {
133			return fmt.Errorf("bead: marshal claim liveness: %w", err)
134		}
135		data = append(data, '\n')
136		return writeAtomicClaimFile(claimLivenessPath(s.Dir, id), data)
137	}
138	
139	func (s *Store) TouchClaimHeartbeat(id string) error {
140		return s.upsertClaimHeartbeat(id, nil)
141	}
142	
143	func (s *Store) RemoveClaimHeartbeat(id string) error {
144		err := os.Remove(claimLivenessPath(s.Dir, id))
145		if err == nil || os.IsNotExist(err) {
146			return nil
147		}
148		return fmt.Errorf("bead: remove claim liveness: %w", err)
149	}
150	
151	func (s *Store) ClaimHeartbeatFresh(id string) (bool, bool, error) {
152		rec, found, err := s.readClaimHeartbeat(id)
153		if err != nil {
154			return false, false, err
155		}
156		if !found {
157			return false, false, nil
158		}
159		if rec.UpdatedAt.IsZero() {
160			return false, true, nil
161		}
162		return time.Since(rec.UpdatedAt) <= HeartbeatTTL, true, nil
163	}
