185	// exists. The record is the operator-facing live claim surface for workers; the
186	// tracker still carries any explicit manual lifecycle status change.
187	func (s *Store) ClaimLease(id string) (ClaimLeaseRecord, bool, error) {
188		return s.readClaimHeartbeat(id)
189	}

