111	// WriteRunState atomically writes state to a per-attempt file under
112	// .ddx/run-state/ and refreshes .ddx/run-state.json as a legacy compatibility
113	// summary. Writes go to sibling tmp files and are then renamed into place so
114	// readers never observe a partial record.
115	func WriteRunState(projectRoot string, state RunState) error {
116		if projectRoot == "" {
