 20	// LiveWorker describes one running ddx worker process.
 21	type LiveWorker struct {
 22		PID               int       `json:"pid"`
 23		Command           string    `json:"command"`
 24		StartedAt         time.Time `json:"started_at"`
 25		AgeSeconds        float64   `json:"age_seconds"`
 26		Age               string    `json:"age"`
 27		ProjectRoot       string    `json:"project_root"`
 28		BeadID            string    `json:"bead_id,omitempty"`
 29		AttemptID         string    `json:"attempt_id,omitempty"`
 30		Phase             string    `json:"phase,omitempty"`
 31		Message           string    `json:"message,omitempty"`
 32		ChildPID          int       `json:"child_pid,omitempty"`
 33		LastActivityAt    time.Time `json:"last_activity_at,omitempty"`
 34		ExecutionWorktree string    `json:"execution_worktree,omitempty"`
 35		Cwd               string    `json:"cwd,omitempty"`
 36	}
