121	// FilterByProject returns workers whose ProjectRoot resolves to the same path
122	// as projectRoot. Resolution canonicalises both sides via filepath.Abs and
123	// filepath.EvalSymlinks so a symlinked checkout matches its real path.
124	func FilterByProject(workers []LiveWorker, projectRoot string) []LiveWorker {
125		target := canonicalPath(projectRoot)
126		out := make([]LiveWorker, 0, len(workers))
127		for _, w := range workers {
128			if SamePath(w.ProjectRoot, target) {
129				out = append(out, w)
130			}
131		}
132		return out
133	}
