135	// SamePath reports whether a and b refer to the same on-disk location after
136	// canonicalisation. It tolerates empty inputs (returning false) so callers
137	// can safely compare optional fields without prefiltering.
138	func SamePath(a, b string) bool {
139		ca := canonicalPath(a)
140		cb := canonicalPath(b)
141		if ca == "" || cb == "" {
142			return false
143		}
144		return ca == cb
145	}
146	
147	func canonicalPath(p string) string {
148		if strings.TrimSpace(p) == "" {
149			return ""
150		}
151		abs, err := filepath.Abs(p)
152		if err != nil {
153			abs = filepath.Clean(p)
154		}
155		if resolved, err := filepath.EvalSymlinks(abs); err == nil {
156			return resolved
157		}
158		return abs
159	}
