 18	// resolveProjectRoot resolves the target project root from CLI flags,
 19	// environment, or the current working directory.
 20	func resolveProjectRoot(projectFlag, workingDir string) string {
 21		if projectFlag != "" {
 22			return projectFlag
 23		}
 24		if env := os.Getenv("DDX_PROJECT_ROOT"); env != "" {
 25			return env
 26		}
