 31		if workingDir == "" {
 32			return ""
 33		}
 34		if workspaceRoot := gitpkg.FindNearestDDxWorkspace(workingDir); workspaceRoot != "" {
 35			return workspaceRoot
 36		}
 37		return workingDir
 38	}
