 44	type preClaimGitOps interface {
 45		CurrentBranch(dir string) (string, error)
 46		LocalAncestryCheck(dir, targetBranch string) (agent.PreClaimResult, error)
 47	}
 48	
 49	// buildCLIPreClaimHook returns a PreClaimHook for inline queue work that
 50	// verifies the local target branch against the last-observed origin
 51	// remote-tracking ref before each bead claim. It performs no network I/O
 52	// (reliability principle P9): the queue's forward progress is never coupled to
 53	// origin reachability. Origin refresh is operator-driven via `ddx sync`.
 54	func buildCLIPreClaimHook(projectRoot string, gitOps preClaimGitOps) func(ctx context.Context) error {
 55		return func(ctx context.Context) error {
 56			branch, err := gitOps.CurrentBranch(projectRoot)
 57			if err != nil {
 58				return nil // can't determine branch — skip
 59			}
 60			res, err := gitOps.LocalAncestryCheck(projectRoot, branch)
 61			if err != nil {
 62				if !agent.IsIgnorableFetchOriginError(err) {
 63					return err
 64				}
 65				return nil
 66			}
 67			if res.Action == "diverged" {
 68				return fmt.Errorf("local branch %s has diverged from origin (local=%s origin=%s); reconcile manually before claiming",
 69					branch, res.LocalSHA, res.OriginSHA)
 70			}
 71			return nil
 72		}
 73	}
 74	
 75	func buildCLIResourceChecker(projectRoot string, override agent.ExecutionResourceChecker) agent.ExecutionResourceChecker {
 76		if override != nil {
 77			return override
 78		}
 79		return agent.NewExecutionResourceChecker(projectRoot, &agent.RealGitOps{})
 80	}
