 82	// resolveServerURL determines the base URL for the running DDx server.
 83	func resolveServerURL(projectRoot string) string {
 84		if u := os.Getenv("DDX_SERVER_URL"); u != "" {
 85			return u
 86		}
 87		if u := serverpkg.ReadServerAddr(); u != "" {
 88			return rewriteBindAddrForClient(u)
 89		}
 90		return "https://127.0.0.1:7743"
 91	}
 92	
 93	func rewriteBindAddrForClient(u string) string {
 94		for _, bind := range []string{"//0.0.0.0:", "//[::]:", "//[::0]:"} {
 95			if idx := strings.Index(u, bind); idx >= 0 {
 96				return u[:idx] + "//127.0.0.1:" + u[idx+len(bind):]
 97			}
 98		}
 99		return u
100	}
