335		count := 0
336		for _, entry := range entries {
337			if entry.IsDir() || filepath.Ext(entry.Name()) != ".json" {
338				continue
339			}
340			data, err := os.ReadFile(filepath.Join(runStateDir, entry.Name()))
341			if err != nil {
