package activework

import (
	"context"
	"sort"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/agent"
	"github.com/DocumentDrivenDX/ddx/internal/bead"
	"github.com/DocumentDrivenDX/ddx/internal/workerstatus"
)

// Record describes one fresh source of active work for a bead.
//
// The snapshot reconciles claim-heartbeat leases, worker liveness sidecars,
// and fresh run-state records into one project-scoped view so operator-facing
// status surfaces can agree on what is actively running.
type Record struct {
	WorkerID       string    `json:"worker_id,omitempty"`
	BeadID         string    `json:"bead_id,omitempty"`
	AttemptID      string    `json:"attempt_id,omitempty"`
	Owner          string    `json:"owner,omitempty"`
	Phase          string    `json:"phase,omitempty"`
	Source         string    `json:"source,omitempty"`
	LastActivityAt time.Time `json:"last_activity_at"`
}

// Snapshot is the shared active-work summary used by bead, work, and GraphQL
// status views.
type Snapshot struct {
	Count   int      `json:"count"`
	BeadIDs []string `json:"bead_ids"`
	Records []Record `json:"records"`
}

// Collect returns a fresh active-work snapshot for projectRoot.
//
// A record is considered active when it is fresh under the source-specific
// freshness window:
// - claim heartbeats: bead.HeartbeatTTL
// - worker sidecars: workerstatus.LivenessTTL
// - run-state files: their ExpiresAt timestamp
//
// Stale records are ignored.
func Collect(projectRoot string, store *bead.Store, now time.Time) (Snapshot, error) {
	byKey := make(map[string]Record)

	add := func(rec Record) {
		key := activeWorkKey(rec)
		if key == "" {
			return
		}
		if existing, ok := byKey[key]; ok {
			byKey[key] = mergeRecord(existing, rec)
			return
		}
		byKey[key] = rec
	}

	if store != nil {
		beads, err := store.ReadAll(context.Background())
		if err != nil {
			return Snapshot{}, err
		}
		for _, b := range beads {
			if b.Status != bead.StatusOpen && b.Status != bead.StatusInProgress {
				continue
			}
			lease, found, err := store.ClaimLease(b.ID)
			if err != nil || !found || lease.UpdatedAt.IsZero() {
				continue
			}
			if now.Sub(lease.UpdatedAt) > bead.HeartbeatTTL {
				continue
			}
			add(Record{
				BeadID:         b.ID,
				WorkerID:       lease.Owner,
				Owner:          lease.Owner,
				Source:         "claim",
				LastActivityAt: lease.UpdatedAt.UTC(),
			})
		}
	}

	if projectRoot != "" {
		liveness, err := workerstatus.ListLiveness(projectRoot)
		if err != nil {
			return Snapshot{}, err
		}
		for _, rec := range liveness {
			if !rec.IsFresh(now) {
				continue
			}
			add(Record{
				WorkerID:       rec.WorkerID,
				BeadID:         rec.CurrentBead,
				AttemptID:      rec.AttemptID,
				Phase:          rec.Phase,
				Source:         "liveness",
				LastActivityAt: rec.LastActivityAt.UTC(),
			})
		}

		states, err := agent.ReadRunStates(projectRoot)
		if err != nil {
			return Snapshot{}, err
		}
		for _, state := range states {
			if !state.ExpiresAt.IsZero() && now.After(state.ExpiresAt) {
				continue
			}
			add(Record{
				BeadID:         state.BeadID,
				AttemptID:      state.AttemptID,
				Source:         "run-state",
				LastActivityAt: state.RefreshedAt.UTC(),
			})
		}
	}

	records := make([]Record, 0, len(byKey))
	beadIDs := make(map[string]struct{})
	for _, rec := range byKey {
		records = append(records, rec)
		if rec.BeadID != "" {
			beadIDs[rec.BeadID] = struct{}{}
		}
	}

	sort.SliceStable(records, func(i, j int) bool {
		if records[i].LastActivityAt.Equal(records[j].LastActivityAt) {
			if records[i].BeadID == records[j].BeadID {
				if records[i].AttemptID == records[j].AttemptID {
					if records[i].WorkerID == records[j].WorkerID {
						return records[i].Source < records[j].Source
					}
					return records[i].WorkerID < records[j].WorkerID
				}
				return records[i].AttemptID < records[j].AttemptID
			}
			return records[i].BeadID < records[j].BeadID
		}
		return records[i].LastActivityAt.After(records[j].LastActivityAt)
	})

	beadList := make([]string, 0, len(beadIDs))
	for id := range beadIDs {
		beadList = append(beadList, id)
	}
	sort.Strings(beadList)

	return Snapshot{
		Count:   len(records),
		BeadIDs: beadList,
		Records: records,
	}, nil
}

func activeWorkKey(rec Record) string {
	switch {
	case rec.BeadID != "":
		return "bead:" + rec.BeadID
	case rec.AttemptID != "":
		return "attempt:" + rec.AttemptID
	case rec.WorkerID != "":
		return "worker:" + rec.WorkerID
	default:
		return ""
	}
}

func mergeRecord(dst, src Record) Record {
	if src.LastActivityAt.After(dst.LastActivityAt) {
		if src.BeadID != "" {
			dst.BeadID = src.BeadID
		}
		if src.AttemptID != "" {
			dst.AttemptID = src.AttemptID
		}
		if src.WorkerID != "" {
			dst.WorkerID = src.WorkerID
		}
		if src.Owner != "" {
			dst.Owner = src.Owner
		}
		if src.Phase != "" {
			dst.Phase = src.Phase
		}
		if src.Source != "" {
			dst.Source = src.Source
		}
		dst.LastActivityAt = src.LastActivityAt
		return dst
	}
	if dst.BeadID == "" {
		dst.BeadID = src.BeadID
	}
	if dst.AttemptID == "" {
		dst.AttemptID = src.AttemptID
	}
	if dst.WorkerID == "" {
		dst.WorkerID = src.WorkerID
	}
	if dst.Owner == "" {
		dst.Owner = src.Owner
	}
	if dst.Phase == "" {
		dst.Phase = src.Phase
	}
	if dst.Source == "" {
		dst.Source = src.Source
	}
	if dst.LastActivityAt.IsZero() {
		dst.LastActivityAt = src.LastActivityAt
	}
	return dst
}

package workerstatus

import (
	"encoding/json"
	"fmt"
	"os"
	"path/filepath"
	"sort"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/ddxroot"
)

// LivenessRecord is the worker-side sidecar written under
// .ddx/workers/<worker-id>/status.json to mirror live progress of a
// long-running ddx work / ddx try attempt without rewriting beads.jsonl.
//
// The bead tracker remains the durable claim marker; this sidecar carries
// the high-frequency liveness signal so operators can answer "is the worker
// alive and what is it doing?" without inflating tracker churn.
type LivenessRecord struct {
	WorkerID       string    `json:"worker_id"`
	ProjectRoot    string    `json:"project_root,omitempty"`
	CurrentBead    string    `json:"current_bead,omitempty"`
	AttemptID      string    `json:"attempt_id,omitempty"`
	Phase          string    `json:"phase,omitempty"`
	Message        string    `json:"message,omitempty"`
	Route          string    `json:"route,omitempty"`
	Harness        string    `json:"harness,omitempty"`
	Model          string    `json:"model,omitempty"`
	Profile        string    `json:"profile,omitempty"`
	PID            int       `json:"pid,omitempty"`
	ChildPID       int       `json:"child_pid,omitempty"`
	StartedAt      time.Time `json:"started_at,omitempty"`
	LastActivityAt time.Time `json:"last_activity_at"`
}

// LivenessTTL is the freshness window for treating a worker sidecar as
// "active". Defaults to 3× the bead tracker heartbeat interval (which is
// 30s) so a sidecar that has not been touched in ~90s is treated as stale.
var LivenessTTL = 90 * time.Second

// LivenessDir returns the worker sidecar directory for a project.
func LivenessDir(projectRoot string) string {
	return ddxroot.JoinProject(projectRoot, "workers")
}

// LivenessPath returns the status.json path for a worker under projectRoot.
func LivenessPath(projectRoot, workerID string) string {
	return filepath.Join(LivenessDir(projectRoot), workerID, "status.json")
}

// WriteLiveness writes rec to .ddx/workers/<workerID>/status.json using a
// tmp-then-rename so concurrent readers never see a half-written file.
func WriteLiveness(projectRoot, workerID string, rec LivenessRecord) error {
	if projectRoot == "" || workerID == "" {
		return fmt.Errorf("workerstatus: project root and worker id required")
	}
	dir := filepath.Join(LivenessDir(projectRoot), workerID)
	if err := os.MkdirAll(dir, 0o755); err != nil {
		return fmt.Errorf("workerstatus: mkdir worker dir: %w", err)
	}
	data, err := json.MarshalIndent(rec, "", "  ")
	if err != nil {
		return fmt.Errorf("workerstatus: marshal liveness: %w", err)
	}
	data = append(data, '\n')
	final := filepath.Join(dir, "status.json")
	tmp, err := os.CreateTemp(dir, "status-*.tmp")
	if err != nil {
		return fmt.Errorf("workerstatus: create tmp: %w", err)
	}
	tmpName := tmp.Name()
	if _, err := tmp.Write(data); err != nil {
		_ = tmp.Close()
		_ = os.Remove(tmpName)
		return fmt.Errorf("workerstatus: write tmp: %w", err)
	}
	if err := tmp.Close(); err != nil {
		_ = os.Remove(tmpName)
		return fmt.Errorf("workerstatus: close tmp: %w", err)
	}
	if err := os.Rename(tmpName, final); err != nil {
		_ = os.Remove(tmpName)
		return fmt.Errorf("workerstatus: rename: %w", err)
	}
	return nil
}

// ReadLiveness reads the sidecar for workerID under projectRoot.
func ReadLiveness(projectRoot, workerID string) (LivenessRecord, error) {
	var rec LivenessRecord
	data, err := os.ReadFile(LivenessPath(projectRoot, workerID))
	if err != nil {
		return rec, err
	}
	if err := json.Unmarshal(data, &rec); err != nil {
		return rec, fmt.Errorf("workerstatus: parse liveness: %w", err)
	}
	return rec, nil
}

// ListLiveness reads every status.json sidecar under projectRoot's worker
// directory. Malformed sidecars are skipped silently — the sidecar is
// best-effort observability, not authoritative state.
func ListLiveness(projectRoot string) ([]LivenessRecord, error) {
	dir := LivenessDir(projectRoot)
	entries, err := os.ReadDir(dir)
	if err != nil {
		if os.IsNotExist(err) {
			return nil, nil
		}
		return nil, err
	}
	var out []LivenessRecord
	for _, entry := range entries {
		if !entry.IsDir() {
			continue
		}
		rec, err := ReadLiveness(projectRoot, entry.Name())
		if err != nil {
			continue
		}
		out = append(out, rec)
	}
	sort.Slice(out, func(i, j int) bool {
		return out[i].LastActivityAt.After(out[j].LastActivityAt)
	})
	return out, nil
}

// IsFresh reports whether rec.LastActivityAt is within LivenessTTL of now.
func (r LivenessRecord) IsFresh(now time.Time) bool {
	if r.LastActivityAt.IsZero() {
		return false
	}
	return now.Sub(r.LastActivityAt) <= LivenessTTL
}

